return ['domain'=>NULL,'plural-forms'=>'nplurals=1; plural=0;','language'=>'zh_TW','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'請將 TranslatePress - Multilingual 外掛更新至版本 %1$s 或更高版本，以確保 %2$s 正常運作。','Please install and activate the TranslatePress - Multilingual plugin'=>'請安裝並啟用 TranslatePress - Multilingual 外掛','Install & Activate'=>'安裝並啟用','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'請將 TranslatePress - Multilingual 更新至版本 %2$s 或更新版本。您目前安裝的 TranslatePress - Multilingual 版本與目前 %1$s 版本不再相容。','All TranslatePress functionalities are disabled until then.'=>'在此之前，所有 TranslatePress 功能都將停用。','Update Now'=>'立即更新','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'此 TranslatePress 附加元件已移轉至主要外掛，不再使用。您可以將其刪除。','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> 至少需要 PHP 5.6.20+ 版本才能執行。這是<a href="%s">最新 WordPress 版本的最低需求</a>。請聯絡您的伺服器管理員更新 PHP 版本。','Advanced'=>'進階','Settings saved.'=>'設定已儲存。','Are you sure you want to remove this item?'=>'確定要移除此項目嗎？','Remove'=>'移除','Add'=>'新增','Select...'=>'選取...','[%s] Low TranslatePress AI Words'=>'[%s] TranslatePress AI 字數不足','upgrade your plan or get extra AI Words'=>'升級您的方案或取得額外 AI 字數','upgrade your plan'=>'升級您的方案','TranslatePress AI words are running low on your site.'=>'您網站上的 TranslatePress AI 字數即將用完。','Current status: %s words remaining'=>'目前狀態：剩餘 %s 字','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'一旦剩餘 AI 字數用完，透過 TranslatePress AI 進行的自動翻譯將會暫停。','To continue translating your content, please %1$s over at %2$s'=>'若要繼續翻譯您的內容，請前往 %2$s %1$s','Manage Notification: %s'=>'管理通知：%s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'%1$s 已有新版本可供使用。%2$s查看版本 %3$s 詳細資訊%4$s，或%5$s立即更新%6$s。','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'%1$s 已有新版本可供使用。%2$s查看版本 %3$s 詳細資訊%4$s。','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'若要啟用更新，請%1$s輸入您的授權金鑰%2$s。需要授權金鑰嗎？%3$s立即購買%4$s。','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'若要啟用更新，請前往%1$s授權頁面%2$s，並確認您擁有有效的授權。','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'若要啟用更新，您的授權需要續約。請前往%1$sTranslatePress Account%2$s頁面並登入以續約。','You do not have permission to install plugin updates'=>'您沒有安裝外掛更新的權限。','Error'=>'錯誤','Your TranslatePress license key is invalid or missing.'=>'您的 TranslatePress 授權金鑰無效或遺失。','Your license key expired on %s.'=>'您的授權金鑰已於 %s 過期。','Your license key has been disabled.'=>'您的授權金鑰已被停用。','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'您的授權金鑰已在此 URL 停用。請從 <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> 管理網站重新啟用。','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>授權金鑰不符。</strong>您輸入的授權與已安裝的 TranslatePress 版本不符。</p><p>請確認您已從 TranslatePress 帳號安裝與授權相符的正確版本。</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'如果您只安裝了免費外掛，但已新增付費授權，請從您的 TranslatePress 帳號安裝付費外掛。','Your license key has reached its activation limit.'=>'您的授權金鑰已達啟用上限。','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'升級您的方案以新增更多網站。%1$s立即升級%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'此網站已在免費授權下啟用。每個網站只能使用一個免費授權。','An error occurred, please try again.'=>'發生錯誤，請再試一次。','You have successfully activated your license'=>'您已成功啟用授權。','Others'=>'其他','Restrict by Language'=>'依語言限制','Exclude from Language'=>'從語言排除','Restrict element to language'=>'限制元素顯示語言','Show this element only in one language.'=>'僅在單一語言中顯示此元素。','Enable translation'=>'啟用翻譯','Allow translation to the corresponding language only if the content is written in the default language.'=>'僅當內容以預設語言撰寫時，才允許翻譯為對應語言。','Select language'=>'選取語言','Choose in which language to show this element.'=>'選擇要以哪種語言顯示此元素。','Exclude element from language'=>'從語言排除元素','Exclude this element from specific languages.'=>'從特定語言排除此元素。','Select languages'=>'選取語言','Choose from which languages to exclude this element.'=>'選擇要從哪些語言排除此元素。','This element will still be visible when you are translating your website through the Translation Editor.'=>'透過翻譯編輯器翻譯網站時，此元素仍會顯示。','The content of this element should be written in the default language.'=>'此元素的內容應以預設語言撰寫。','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> 遇到 SQL 錯誤。<a href="%s" title="View TranslatePress SQL Errors">查看錯誤</a>。','Automatic translation has been disabled.'=>'自動翻譯已停用。','Dismiss this notice.'=>'忽略此通知。','Logged errors'=>'已記錄的錯誤','These are the most recent 5 errors logged by TranslatePress:'=>'以下是 TranslatePress 記錄的最新的 5 個錯誤：','Yes'=>'是','Why are these errors occuring'=>'為什麼會發生這些錯誤','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'如果 TranslatePress 在執行資料庫查詢時偵測到異常，可能會停用自動翻譯功能，以避免 Google/DeepL 額外收費。解決問題後，需要手動重新開啟自動翻譯。','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'偵測到的 SQL 錯誤可能由多種原因造成，包括缺少資料表、SQL 使用者缺少建立資料表或執行其他操作的權限、網站遷移後的問題，或是 SQL 伺服器設定變更。','What you can do in this situation'=>'您可以在此情況下怎麼做','Plan A.'=>'方案 A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'前往「設定」->「TranslatePress」->「一般」分頁，然後儲存設定。這會使用您目前的 SQL 設定重新產生資料表。請以翻譯語言瀏覽網站，確認是否不再發生錯誤。請查看錯誤時間戳記，以確保您看到的不是舊錯誤。只會顯示最近 5 筆錯誤。','Plan B.'=>'方案 B.','If your problem isn\'t solved, try the following steps:'=>'如果問題尚未解決，請嘗試以下步驟：','Create a backup of your database'=>'建立資料庫備份','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'為每個發生錯誤的翻譯資料表建立副本。您可以在同一個資料庫內複製資料表（例如 trp_dictionary_en_us_es_es_COPY）——只有當您想保留目前翻譯時，才執行此步驟。','Remove the trouble tables by executing the DROP function on them'=>'執行 DROP 函式來移除有問題的資料表','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'前往「設定」->「TranslatePress」->「一般」分頁，然後儲存設定。這會使用您目前的 SQL 伺服器重新產生資料表。','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'將複製資料表中的相關內容（例如 trp_dictionary_en_us_es_es_COPY）複製到新產生的資料表（trp_dictionary_en_us_es_es）中——只有當您想保留目前翻譯時，才執行此步驟。','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'進行測試以確認一切正常。如果發生問題，您可以還原第一步建立的備份。請以翻譯語言瀏覽網站，確認是否不再發生錯誤。請查看錯誤時間戳記，以確保您看到的不是舊錯誤。只會顯示最近 5 筆錯誤。','Plan C.'=>'方案 C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'如果問題仍未解決，請嘗試向您的主機商詢問這些錯誤。最常見的問題是 SQL 使用者缺少權限，例如建立資料表的權限。','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'無法安裝。請從<a href="%s" >外掛程式頁面</a>再試一次。','Active'=>'已啟用','Permission denied.'=>'沒有權限。','Invalid nonce.'=>'無效的 nonce。','Settings scope unknown.'=>'設定範圍未知。','Legacy disabled.'=>'舊版功能已停用。','Language Switcher'=>'語言切換器','Change language to %s'=>'將語言變更為 %s','Automatic Translation'=>'自動翻譯','DeepL'=>'DeepL','Unsupported languages'=>'不支援的語言','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'選取的自動翻譯引擎不支援這些語言。<br>您仍可使用翻譯編輯器手動翻譯這些語言的頁面。','API key validation failed.'=>'API 金鑰驗證失敗。','API key verification was successful.'=>'API 金鑰驗證成功。','Please enter your Google Translate key.'=>'請輸入您的 Google Translate 金鑰。','Please enter your DeepL API key.'=>'請輸入您的 DeepL API 金鑰。','Not TranslatePress onboarding page.'=>'非 TranslatePress 設定引導頁面。','Step %s does not exist'=>'步驟 %s 不存在','Welcome'=>'歡迎','Add Languages'=>'新增語言','Enable Addons'=>'啟用附加元件','Finalize'=>'完成','Exit Setup'=>'退出設定','Upgrade'=>'升級','Nothing here'=>'尚無內容','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'您的 <strong>TranslatePress</strong> 授權遺失或無效。<br/>請 %1$s註冊您的副本%2$s，以啟用透過 TranslatePress AI 提供的自動網站翻譯、進階附加元件、自動更新及支援服務。需要授權金鑰嗎？%3$s立即購買%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'您的 <strong>TranslatePress</strong> 授權將於 %1$s 到期。請 %2$s續約您的授權%3$s，以繼續使用透過 TP AI 提供的自動翻譯、進階附加元件、產品下載及自動更新服務。%4$s立即續約%5$s','Error: '=>'錯誤： ','Something went wrong, please try again.'=>'發生錯誤，請再試一次。','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'您的 <strong>TranslatePress</strong> 授權已到期。<br/>請 %1$s續約您的授權%2$s，以繼續使用透過 TranslatePress AI 提供的自動翻譯、進階附加元件、產品下載及自動更新服務。%3$s立即續約 %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'授權金鑰不符。您輸入的授權與您已安裝的 <strong>%1$s</strong> 版本不相符。<br/>請在您的 %2$sTranslatePress Account%3$s 中確認您已安裝與授權相符的正確版本。','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>如果您只安裝了免費版外掛，但新增了付費授權，請從您的 TranslatePress Account 安裝付費版外掛。','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'您的 <strong>%1$s</strong> 授權已達啟用數量上限。<br/>從 %2$s 您的帳號 %3$s 管理已啟用的網站。','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'您的授權已在此 URL 停用。請前往 <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> 管理網站 重新啟用。','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s 自動翻譯需要有效的授權。請 %2$s續約%3$s 您的授權，或 %4$s在此處%5$s 購買新的授權。','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'請 %1$s輸入%2$s 您的授權金鑰，以啟用 %3$s 自動翻譯。','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'您的 TranslatePress AI 剩餘字數已不足 5,000。若要繼續自動翻譯您的網站，請 %s從您的帳號以折扣價購買額外的 AI 字數%s。',' Error: '=>' 錯誤： ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'此網站已在免費授權下啟用。每個網站只能使用一個免費授權。請從 %1$s 您的帳號 %2$s 升級至進階方案，以取得更多 TranslatePress AI 字數。','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'您沒有有效的 <strong>TranslatePress</strong> 授權。%1$s免費取得%2$s，以使用 TranslatePress AI。','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>新功能：</strong><strong>Different Domain per Language</strong> 附加元件已推出！提升您的全球 SEO，並使用 .de 或 .fr 等國家專屬域名打造在地化體驗。升級至 <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business 或 Developer</a> 即可使用，並享有更多進階權益！','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>新功能：</strong><strong>Different Domain per Language</strong> 附加元件已推出！提升您的全球 SEO，並使用 .de 或 .fr 等國家專屬域名打造在地化體驗。<a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">了解更多</a>。','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'機器翻譯字元的每日配額已超過。請查看 <strong>TranslatePress -> <a href="%s">自動翻譯</a></strong> 頁面以取得更多資訊。','Marketing optin'=>'行銷選擇加入','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'選擇加入我們的安全與功能更新通知，以及非敏感性的診斷追蹤。','TranslatePress Preferred User Language'=>'TranslatePress 使用者偏好語言','Preferred language to navigate the site'=>'用於瀏覽網站的偏好語言','The language is automatically set based by the last visited language by the user.'=>'語言會根據使用者上次造訪的語言自動設定。','Always use this language'=>'一律使用此語言','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'勾選此設定後，偏好語言將維持為上方選擇的語言，無法在前台變更。<br>此語言將用於不同操作，例如向使用者發送電子郵件。','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'你好！看來你已經使用 <strong>TranslatePress</strong> 翻譯網站一段時間了。太棒了！ ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'如果你能花幾分鐘在 WordPress.org 上評分，對我們會是很大的幫助（也能激勵我）。','~ Razvan, developer of TranslatePress'=>'~ Razvan，TranslatePress 開發者','Rate TranslatePress on WordPress.org plugin page'=>'在 WordPress.org 外掛頁面為 TranslatePress 評分','Ok, I will gladly help!'=>'好的，我很樂意幫忙！','No, thanks.'=>'不用了，謝謝。','Full Language Names'=>'完整語言名稱','Short Language Names'=>'簡短語言名稱','Flags with Full Language Names'=>'旗幟與完整語言名稱','Flags with Short Language Names'=>'旗幟與簡短語言名稱','Only Flags'=>'僅旗幟','Full Language Names No HTML'=>'完整語言名稱（無 HTML）','Bottom Right'=>'右下角','Bottom Left'=>'左下角','Top Right'=>'右上角','Top Left'=>'左上角','Dark'=>'深色','Light'=>'淺色','Deactivate'=>'停用','Activate'=>'啟用','Invalid language code. Please try again.'=>'語言代碼無效。請再試一次。','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'語言代碼只能包含 A-Z a-z 0-9 - _ 字元。請在 TranslatePress 一般設定中檢查你的語言代碼。','Error! Duplicate URL slug values.'=>'錯誤！重複的 URL slug 值。','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'你無法選擇兩個具有相同 <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso 代碼</a> 但不同正式程度的語言，因為這樣會導致重複的 <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang 標籤</a>。','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'偵測到重複的語言。<br>每種語言只能新增一次，以確保翻譯管理準確無誤。<br> 請變更重複的語言項目，然後再試一次。 ','Current Language'=>'目前語言','Opposite Language'=>'對應語言','General'=>'一般','Translate Site'=>'翻譯網站','Addons'=>'附加元件','License'=>'授權','Settings'=>'設定','Activate License'=>'啟用授權','Pro Features'=>'專業功能','Need Help?'=>'需要協助嗎？','Recent community discussions'=>'最近的社群討論','Loading...'=>'載入中...','Unable to load forum posts'=>'無法載入論壇文章','Ask a Question'=>'提出問題','View All Topics'=>'查看所有主題','by'=>'由','Have a question?'=>'有問題嗎？','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'直接向外掛開發者尋求協助、提出改進建議，或分享你的意見回饋！','Tip for faster help:'=>'更快獲得協助的訣竅：','Include what you tried, what you expected, and what happened. Screenshots help!'=>'請包含您嘗試過的方法、預期的結果，以及實際發生的情況。截圖很有幫助！','Toggle support chat'=>'切換支援對話','Ask the community'=>'向社群發問','Close'=>'關閉','Empty feed response'=>'Feed 回應為空','Unable to parse feed'=>'無法解析 Feed','Just now'=>'剛剛','%d hour ago'=>'%d 小時前','%d day ago'=>'%d 天前','Source'=>'來源','Srcset'=>'Srcset','Alt attribute'=>'替代文字屬性','Title attribute'=>'標題屬性','Anchor link'=>'錨點連結','Placeholder attribute'=>'預留位置屬性','Submit attribute'=>'提交屬性','Text'=>'文字','Video Poster'=>'影片海報','plural form'=>'複數形式','one'=>'單數','few'=>'少數','many'=>'多數','other'=>'其他','Saved'=>'已儲存','Save'=>'儲存','Saving translation...'=>'儲存翻譯中……','You have unsaved changes!'=>'你有未儲存的變更！','Discard changes'=>'捨棄變更','Discard All'=>'全部捨棄','Loading Strings...'=>'正在載入字串...','Select string to translate...'=>'選取要翻譯的字串...','Close Editor'=>'關閉編輯器','From'=>'來源','To'=>'目標','Add Media'=>'新增媒體','Other languages'=>'其他語言','Context'=>'語境','View Website As'=>'檢視網站為','Available in our Pro Versions'=>'我們的專業版提供此功能','Select or Upload Media'=>'選取或上傳媒體','Use this media'=>'使用此媒體','Translate'=>'翻譯','Translate entire block element'=>'翻譯整個區塊元素','Split block to translate strings individually'=>'分割區塊以單獨翻譯字串','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'儲存翻譯變更。快速鍵：CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'導覽至下拉清單中的下一個字串。快速鍵：CTRL(⌘) + ALT + 向右鍵','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'導覽至下拉清單中的上一個字串。快速鍵：CTRL(⌘) + ALT + 向左鍵','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'捨棄所有變更。快速鍵：CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'捨棄此文字方塊的變更。若要捨棄所有文字方塊的變更，請使用快速鍵：CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'關閉工具提示','Quick Intro'=>'快速介紹','Are you sure you want to split this phrase into smaller parts?'=>'確定要將這個片語拆分成較小的部分嗎？','This string is not ready for translation yet. <br>Try again in a moment...'=>'這個字串尚未準備好進行翻譯。<br>請稍後再試...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'若要使用此選項，請將 Browse as other role 附加元件更新至最新版本。','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'若要翻譯 slug，請將 SEO Pack 附加元件更新至最新版本。','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'您可以從<a href="%s">設定->TranslatePress</a>新增語言。','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'不過，你仍然可以使用 TranslatePress 來<strong style="background: #f5fb9d;">修改頁面中可用的 Gettext 字串</strong>。','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'使用者建立的字串無法修改，只有佈景主題和外掛程式中的字串才能修改。','Extra Translation Features'=>'額外翻譯功能','Support for 130+ Extra Languages'=>'支援 130 多種額外語言','Access to TranslatePress AI'=>'可使用 TranslatePress AI','Translate SEO Title, Description, Slug'=>'翻譯 SEO 標題、描述、Slug','Publish only when translation is complete'=>'翻譯完成後